import microcoapy
from machine import Pin

# create server socket using UDP protocol suitable for serving CoAP requests
server = microcoapy.Coap()

# temperature sensor and light actuator representation
temperature = 25.5
light = False

def getTemperature(packet, senderIp, senderPort):
    global temperature
    message = str(temperature).encode()
    server.sendResponse(senderIp, senderPort, packet.messageid, message, microcoapy.COAP_RESPONSE_CODE.COAP_CONTENT, microcoapy.COAP_CONTENT_FORMAT.COAP_NONE, packet.token)

def toggleLight(packet, senderIp, senderPort):
    global light
    payload = packet.payload.decode().lower()
    light = payload == 'true'
    response = 'true' if light else 'false'
    message = response.encode()
    server.sendResponse(senderIp, senderPort, packet.messageid, message, microcoapy.COAP_RESPONSE_CODE.COAP_CONTENT, microcoapy.COAP_CONTENT_FORMAT.COAP_NONE, packet.token)

# assign callback functions to process incoming requests
server.addIncomingRequestCallback('/sensors/temp', getTemperature)
server.addIncomingRequestCallback('/actuators/light', toggleLight)

server.start()